import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import dayjs from "dayjs";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function RoleManagement() {
  const [roles, setRoles] = useState([]);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    id: null,
    name: "",
    description: "",
  });

  const [filters, setFilters] = useState({
    search: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const rolesPerPage = 10;

  const modalRef = useRef(null);
  const navigate = useNavigate();

  /* ================= FETCH ================= */
  function fetchRoles() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/roles", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setRoles(res.data.data);
        } else {
          toast.error("Failed to fetch roles");
        }
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Error fetching roles"),
      )
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchRoles();
  }, [navigate]);

  /* ================= INPUT ================= */
  function handleInputChange(e) {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  }

  /* ================= FILTER ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  /* ================= ADD ================= */
  function openAddModal() {
    setFormData({
      id: null,
      name: "",
      description: "",
    });

    const modalEl = document.getElementById("roleModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= EDIT ================= */
  function openEditModal(role) {
    setFormData(role);

    const modalEl = document.getElementById("roleModal");
    modalRef.current = new Modal(modalEl);
    modalRef.current.show();
  }

  /* ================= DELETE ================= */
  function handleDelete(id) {
    const token = Cookies.get("adminToken");

    if (!window.confirm("Are you sure you want to delete this role?")) return;

    axios
      .delete(API_BASE_URL + "/roles/" + id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Role deleted successfully");
        fetchRoles();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Delete failed"),
      );
  }

  /* ================= SUBMIT ================= */
  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    const request = formData.id
      ? axios.put(API_BASE_URL + "/roles/" + formData.id, formData, {
          headers: { Authorization: "Bearer " + token },
        })
      : axios.post(API_BASE_URL + "/roles", formData, {
          headers: { Authorization: "Bearer " + token },
        });

    request
      .then(() => {
        toast.success(
          formData.id
            ? "Role updated successfully"
            : "Role created successfully",
        );
        fetchRoles();
        modalRef.current.hide();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Operation failed"),
      );
  }

  /* ================= FILTERED DATA ================= */
  const filteredRoles = roles.filter((role) =>
    filters.search
      ? (role.name + role.description)
          .toLowerCase()
          .includes(filters.search.toLowerCase())
      : true,
  );

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * rolesPerPage;
  const indexOfFirst = indexOfLast - rolesPerPage;
  const currentRoles = filteredRoles.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredRoles.length / rolesPerPage);

  function goToNextPage() {
    if (currentPage < totalPages) setCurrentPage((prev) => prev + 1);
  }

  function goToPreviousPage() {
    if (currentPage > 1) setCurrentPage((prev) => prev - 1);
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      {/* Back */}
      <div className="row mb-3">
        <div className="col">
          <i
            className="fa fa-arrow-left mt-2"
            style={{ cursor: "pointer" }}
            onClick={() => navigate("/dashboard")}
          ></i>
        </div>
      </div>

      {/* Header */}
      <div className="row g-3 mb-3">
        <div className="col-md-10 col-7">
          <h4 className="fw-bold mb-0">Roles</h4>
        </div>
        <div className="col-md-2 col-5 text-end">
          <button className="btn btn-primary btn-sm" onClick={openAddModal}>
            + Add Role
          </button>
        </div>
      </div>

      {/* Search */}
      <div className="row g-3 mb-3">
        <div className="col-md-6">
          <input
            type="text"
            name="search"
            className="form-control form-control-sm"
            placeholder="Search Role Name or Description"
            value={filters.search}
            onChange={handleFilterChange}
          />
        </div>
      </div>

      {/* Table */}
      <div className="card border-0 mb-3">
        <div className="card-body p-0">
          {loading ? (
            <div className="text-center p-3">Loading...</div>
          ) : (
            <div className="table-responsive rounded">
              <table className="table table-striped table-hover align-middle mb-0 small">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Role Name</th>
                    <th>Description</th>
                    <th>Created</th>
                    <th>Updated</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {currentRoles.map((role) => (
                    <tr key={role.id}>
                      <td>{role.id}</td>
                      <td>{role.name}</td>
                      <td>{role.description}</td>
                      <td>
                        {dayjs(role.createdAt).format(
                          "DD MMM YYYY, hh:mm A",
                        )}
                      </td>
                      <td>
                        {dayjs(role.updatedAt).format(
                          "DD MMM YYYY, hh:mm A",
                        )}
                      </td>
                      <td>
                        <i
                          className="fa-solid fa-pen-to-square text-primary me-3"
                          style={{ cursor: "pointer" }}
                          onClick={() => openEditModal(role)}
                        ></i>

                        <i
                          className="fa-solid fa-trash text-danger"
                          style={{ cursor: "pointer" }}
                          onClick={() => handleDelete(role.id)}
                        ></i>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      {/* Pagination */}
      <div className="d-flex justify-content-between align-items-center mb-3">
        <div>
          Page {currentPage} of {totalPages} • {filteredRoles.length} records
        </div>
        <div>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === 1}
            onClick={goToPreviousPage}
          >
            <i className="fa-solid fa-chevron-left"></i>
          </button>
          <button
            className="btn btn-sm border-0"
            disabled={currentPage === totalPages || totalPages === 0}
            onClick={goToNextPage}
          >
            <i className="fa-solid fa-chevron-right"></i>
          </button>
        </div>
      </div>

      {/* Modal */}
      <div className="modal fade" id="roleModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content border-0">
            <div className="modal-header">
              <h5 className="modal-title">
                {formData.id ? "Edit Role" : "Add Role"}
              </h5>
              <button
                type="button"
                className="btn-close"
                data-bs-dismiss="modal"
              ></button>
            </div>

            <div className="modal-body">
              <div className="mb-3">
                <label className="form-label small text-muted">
                  Role Name <span className="text-danger">*</span>
                </label>
                <input
                  type="text"
                  name="name"
                  className="form-control form-control-sm"
                  value={formData.name}
                  onChange={handleInputChange}
                  required
                />
              </div>

              <div>
                <label className="form-label small text-muted">
                  Description
                </label>
                <textarea
                  name="description"
                  className="form-control form-control-sm"
                  rows="2"
                  value={formData.description}
                  onChange={handleInputChange}
                />
              </div>
            </div>

            <div className="modal-footer">
              <button
                type="button"
                className="btn btn-sm btn-secondary"
                data-bs-dismiss="modal"
              >
                Cancel
              </button>

              <button
                type="button"
                className="btn btn-sm btn-primary"
                onClick={handleSubmit}
              >
                {formData.id ? "Update Role" : "Create Role"}
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default RoleManagement;
